#include<stdio.h>
long long int mod=1000000007;
long long int modpowfast(long long int b,long long int e)
{
	long long int ans=1;
	while(e>0)
	{
		if(e&1)
			ans=(ans*b)%mod;
		b=(b*b)%mod;
		e=e>>1;
	}
	return ans;
}
int main()
{
	long long int p,k,m,x;
	scanf("%lld %lld",&p,&k);
	if(k==0)
	{
		printf("%lld\n",modpowfast(p,p-1));
	}
	else if(k==1)
	{
		printf("%lld\n",modpowfast(p,p));		
	}
	else
	{
		x=k;
		for(m=1;x!=1;m++)
		{
			x=(x*k)%p;
		}
		printf("%lld\n",modpowfast(p,(p-1)/m));
	}
	return 0;
}

