const M: i64 = 1_000_000_007;

fn fexp(mut x: i64, mut e: i64) -> i64 {
    let mut ans = 1;
    while e > 0 {
        if e & 1 != 0 {
            ans = (ans * x) % M;
        }

        x = (x * x) % M;
        e >>= 1;
    }
    ans
}

struct DSU {
    p: Vec<usize>,
    s: Vec<usize>,
}

impl DSU {
    fn new(n: usize) -> Self {
        Self {
            p: (0..n).collect(),
            s: vec![1; n],
        }
    }

    fn find(&mut self, i: usize) -> usize {
        if self.p[i] != i {
            self.p[i] = self.find(self.p[i]);
        }
        self.p[i]
    }

    fn union(&mut self, mut i: usize, mut j: usize) -> usize {
        i = self.find(i);
        j = self.find(j);
        if i == j { return i; }
        let (i, j) = if self.s[i] < self.s[j] { (i, j) } else { (j, i) };
        self.p[i] = j;
        self.s[j] += self.s[i];
        j
    }

    fn classes(&mut self) -> impl Iterator<Item=usize> {
        let n = self.p.len();
        (0..n).map(|x| self.find(x)).collect::<BTreeSet<_>>().into_iter()
    }
}

fn main() -> Result<(), io::Error> {
    let (stdin, stdout) = (io::stdin(), io::stdout());
    let mut scan = UnsafeScanner::new(stdin.lock());
    let mut out = BufWriter::new(stdout.lock());

    let p: usize = scan.token();
    let k: i64 = scan.token();

    match k {
        0 => { return answer!(out, fexp(p as i64, p as i64 - 1)); }
        1 => { return answer!(out, fexp(p as i64, p as i64)); }
        _ => {}
    }

    let mut dsu = DSU::new(p);

    for x in 1..p {
        let y = k * x as i64 % p as i64;
        dsu.union(x, y as usize);
    }

    answer!(out, fexp(p as i64, (dsu.classes().count() - 1) as i64))
}

